class FenwickTree {
    constructor(size) {
        this.n = size;
        this.tree = new Array(this.n + 1).fill(0);
    }

    update(index, delta) {
        while (index <= this.n) {
            this.tree[index] += delta;
            index += index & -index;
        }
    }

    query(index) {
        let res = 0;
        while (index > 0) {
            res += this.tree[index];
            index -= index & -index;
        }
        return res;
    }

    rangeQuery(l, r) {
        return this.query(r) - this.query(l - 1);
    }
}

function solve(nums, queries) {
    const n = nums.length;
    const depths = new Array(n);
    for (let i = 0; i < n; i++) {
        depths[i] = computeDepth(nums[i]);
    }

    const maxDepth = 5;
    const ft = new Array(maxDepth + 1).fill(null).map(() => new FenwickTree(n));

    for (let i = 0; i < n; i++) {
        const d = depths[i];
        ft[d].update(i + 1, 1);
    }

    const answer = [];
    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1];
            const r = q[2];
            const k = q[3];
            const res = ft[k].rangeQuery(l + 1, r + 1);
            answer.push(res);
        } else {
            const idx = q[1];
            const val = q[2];
            const oldD = depths[idx];
            const newD = computeDepth(val);
            ft[oldD].update(idx + 1, -1);
            ft[newD].update(idx + 1, 1);
            nums[idx] = val;
            depths[idx] = newD;
        }
    }

    return answer;
}

function computeDepth(x) {
    let depth = 0;
    while (x !== 1) {
        x = countSetBits(x);
        depth++;
    }
    return depth;
}

function countSetBits(x) {
    let count = 0;
    while (x) {
        x &= x - 1;
        count++;
    }
    return count;
