package main

import "fmt"

type FenwickTree struct {
    n   int
    tree []int
}

func NewFenwickTree(size int) *FenwickTree {
    return &FenwickTree{
        n:   size,
        tree: make([]int, size+1),
    }
}

func (ft *FenwickTree) update(index int, delta int) {
    for ; index <= ft.n; index += index & -index {
        ft.tree[index] += delta
    }
}

func (ft *FenwickTree) query(index int) int {
    res := 0
    for ; index > 0; index -= index & -index {
        res += ft.tree[index]
    }
    return res
}

func (ft *FenwickTree) rangeQuery(l, r int) int {
    return ft.query(r) - ft.query(l-1)
}

func countSetBits(x int64) int {
    count := 0
    for x > 0 {
        x &= x - 1
        count++
    }
    return count
}

func computeDepth(x int64) int {
    depth := 0
    for x != 1 {
        x = int64(countSetBits(x))
        depth++
    }
    return depth
}

func solve(nums []int64, queries [][]int64) []int64 {
    n := len(nums)
    depths := make([]int, n)
    for i := 0; i < n; i++ {
        depths[i] = computeDepth(nums[i])
    }

    maxDepth := 5
    ft := make([]*FenwickTree, maxDepth+1)
    for d := 0; d <= maxDepth; d++ {
        ft[d] = NewFenwickTree(n)
    }

    for i := 0; i < n; i++ {
        d := depths[i]
        ft[d].update(i+1, 1)
    }

    answer := make([]int64, 0)
    for _, q := range queries {
        if q[0] == 1 {
            l := int(q[1])
            r := int(q[2])
            k := int(q[3])
            res := ft[k].rangeQuery(l+1, r+1)
            answer = append(answer, int64(res))
        } else {
            idx := int(q[1])
            val := q[2]
            oldD := depths[idx]
            newD := computeDepth(val)
            ft[oldD].update(idx+1, -1)
            ft[newD].update(idx+1, 1)
            nums[idx] = val
            depths[idx] = newD
        }
    }

    return answer
}
