package main

import "fmt"

// FenwickTree represents a Binary Indexed Tree
type FenwickTree struct {
    n   int
    tree []int
}

func NewFenwickTree(n int) *FenwickTree {
    ft := &FenwickTree{
        n:   n,
        tree: make([]int, n+1),
    }
    return ft
}

func (ft *FenwickTree) Update(index int, delta int) {
    for ; index <= ft.n; index += index & -index {
        ft.tree[index] += delta
    }
}

func (ft *FenwickTree) Query(index int) int {
    res := 0
    for ; index > 0; index -= index & -index {
        res += ft.tree[index]
    }
    return res
}

func (ft *FenwickTree) RangeQuery(l, r int) int {
    return ft.Query(r) - ft.Query(l-1)
}

func computeDepth(x int64) int {
    depth := 0
    for x != 1 {
        x = countSetBits(x)
        depth++
    }
    return depth
}

func countSetBits(x int64) int {
    count := 0
    for x > 0 {
        x &= x - 1
        count++
    }
    return count
}

func solve(nums []int64, queries [][]int64) []int64 {
    n := len(nums)
    maxDepth := 5
    ft := make([]*FenwickTree, maxDepth+1)
    for d := 0; d <= maxDepth; d++ {
        ft[d] = NewFenwickTree(n)
    }

    // Precompute depths for each number
    depths := make([]int, n)
    for i := 0; i < n; i++ {
        depths[i] = computeDepth(nums[i])
    }

    // Initialize Fenwick Trees
    for i := 0; i < n; i++ {
        d := depths[i]
        ft[d].Update(i+1, 1)
    }

    answer := make([]int64, 0, len(queries))
    for _, q := range queries {
        if q[0] == 1 {
            l := q[1].(int64)
            r := q[2].(int64)
            k := q[3].(int64)
            lInt := int(l)
            rInt := int(r)
            kInt := int(k)
            if kInt < 0 || kInt > maxDepth {
                answer = append(answer, 0)
                continue
            }
            res := ft[kInt].RangeQuery(lInt+1, rInt+1)
            answer = append(answer, int64(res))
        } else {
            idx := q[1].(int64)
            val := q[2].(int64)
            idxInt := int(idx)
            oldD := depths[idxInt]
            newD := computeDepth(val)
            ft[oldD].Update(idxInt+1, -1)
            ft[newD].Update(idxInt+1, 1)
            nums[idxInt] = val
            depths[idxInt] = newD
        }
    }

    return answer
}
